import{_ as e,o as t,c as l,ag as n}from"./chunks/framework.gU7RhlGX.js";const u=JSON.parse('{"title":"OpenClaw 接入微信","description":"","frontmatter":{},"headers":[],"relativePath":"openclaw/openclaw 接入微信.md","filePath":"openclaw/openclaw 接入微信.md","lastUpdated":1776422487000}'),o={name:"openclaw/openclaw 接入微信.md"};function s(i,a,r,h,p,d){return t(),l("div",null,[...a[0]||(a[0]=[n('<h1 id="openclaw-接入微信" tabindex="-1">OpenClaw 接入微信 <a class="header-anchor" href="#openclaw-接入微信" aria-label="Permalink to &quot;OpenClaw 接入微信&quot;">​</a></h1><p>OpenClaw（原 Clawdbot）是一个开源、本地优先的 AI 代理网关，支持直接操作电脑、浏览网页、执行命令。通过微信插件接入，可以实现与 AI 代理的无缝对话。</p><hr><h2 id="个人微信一键接入-clawbot-插件" tabindex="-1">个人微信一键接入（ClawBot 插件） <a class="header-anchor" href="#个人微信一键接入-clawbot-插件" aria-label="Permalink to &quot;个人微信一键接入（ClawBot 插件）&quot;">​</a></h2><p>此方案适用于 <strong>iOS 8.0.70+</strong> 版本的个人微信。</p><h3 id="📋-前置条件" tabindex="-1">📋 前置条件 <a class="header-anchor" href="#📋-前置条件" aria-label="Permalink to &quot;📋 前置条件&quot;">​</a></h3><ul><li><strong>微信版本</strong>：iOS 8.0.70 及以上。</li><li><strong>OpenClaw 实例</strong>：已在本地或服务器环境部署并运行。 <ul><li><em>若未安装，可执行：<code>npm install -g openclaw@latest</code></em></li></ul></li></ul><h3 id="🚀-操作步骤" tabindex="-1">🚀 操作步骤 <a class="header-anchor" href="#🚀-操作步骤" aria-label="Permalink to &quot;🚀 操作步骤&quot;">​</a></h3><h4 id="_1-开启微信插件" tabindex="-1">1. 开启微信插件 <a class="header-anchor" href="#_1-开启微信插件" aria-label="Permalink to &quot;1. 开启微信插件&quot;">​</a></h4><p>打开手机微信，依次进入：<strong>我</strong> -&gt; <strong>设置</strong> -&gt; <strong>插件</strong>。</p><h4 id="_2-查找-clawbot" tabindex="-1">2. 查找 ClawBot <a class="header-anchor" href="#_2-查找-clawbot" aria-label="Permalink to &quot;2. 查找 ClawBot&quot;">​</a></h4><p>在插件列表中找到 <strong>「ClawBot」</strong> 卡片并点击进入。在页面中你可以看到相关的安装说明。</p><h4 id="_3-执行安装命令" tabindex="-1">3. 执行安装命令 <a class="header-anchor" href="#_3-执行安装命令" aria-label="Permalink to &quot;3. 执行安装命令&quot;">​</a></h4><p>在运行 OpenClaw 的终端（服务器或本地电脑）中，复制并执行以下命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @tencent-weixin/openclaw-weixin-cli@latest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="_4-扫码绑定" tabindex="-1">4. 扫码绑定 <a class="header-anchor" href="#_4-扫码绑定" aria-label="Permalink to &quot;4. 扫码绑定&quot;">​</a></h4><p>命令执行后，终端会生成一个 <strong>二维码</strong>。使用当前的微信扫码进行身份绑定。</p><h4 id="_5-确认部署成功" tabindex="-1">5. 确认部署成功 <a class="header-anchor" href="#_5-确认部署成功" aria-label="Permalink to &quot;5. 确认部署成功&quot;">​</a></h4><ul><li><strong>终端反馈</strong>：扫码成功后，终端会提示连接成功并自动重启 OpenClaw。</li><li><strong>后台查看</strong>：登录 OpenClaw 管理后台，进入 <strong>「频道 (Channels)」</strong> 页面，确认微信图标已亮起且状态为正常。</li></ul><h4 id="_6-开始对话" tabindex="-1">6. 开始对话 <a class="header-anchor" href="#_6-开始对话" aria-label="Permalink to &quot;6. 开始对话&quot;">​</a></h4><p>现在，你已经可以直接在微信聊天窗口中发送消息，与你的 OpenClaw 智能体进行交互了。</p>',21)])])}const _=e(o,[["render",s]]);export{u as __pageData,_ as default};
